const body = $json.body || $json;
const required = ['request_id', 'workflow_type', 'generated_by', 'client', 'brand', 'campaign', 'brief', 'options', 'design_brief_types', 'safety'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null);
const safety = body.safety || {};
const safetyOk = body.workflow_type === 'design_brief'
  && body.owner_approval_required === true
  && body.generate_images === false
  && safety.no_auto_post === true
  && safety.no_auto_ads === true
  && safety.no_live_connectors === true
  && safety.no_image_generation === true
  && safety.no_secrets === true
  && safety.owner_approval_required === true;
if (missing.length || !safetyOk) {
  return [{ json: {
    ok: false,
    request_id: body.request_id || null,
    error: {
      code: missing.length ? 'INVALID_CONTRACT' : 'REJECTED_BY_SAFETY',
      message: missing.length ? `Missing required fields: ${missing.join(', ')}` : 'Safety flags rejected this request (design briefs are text/spec only, no image generation).'
    },
    status: 'failed',
    owner_approval_required: true,
    safety
  }}];
}
return [{ json: body }];

const request = $json;
const channel = request.options?.channel || 'Facebook';
const goal = request.options?.goal || 'branding';
const brand = request.brand?.name || 'Brand';
const product = request.brief?.product_focus || request.brand?.hero_product || 'hero product';
const audience = request.brief?.target_audience || request.brand?.target_audience || 'core local audience';
const colors = request.brand?.brand_colors || 'brand primary + neutral support, high legibility';
const offer = request.brief?.offer || 'current campaign offer (owner to confirm)';
const specs = [
  { key: 'facebook_post', title: 'Facebook Post Design Brief', platform: channel, format: '1:1 square (1080x1080)', objective: 'Stop the scroll and drive feed engagement' },
  { key: 'story_reels_cover', title: 'Story / Reels Cover Design Brief', platform: 'Story / Reels', format: '9:16 vertical (1080x1920)', objective: 'High-contrast cover that earns the tap' },
  { key: 'menu_promo_visual', title: 'Menu / Promo Visual Design Brief', platform: channel, format: '4:5 portrait (1080x1350)', objective: 'Communicate the offer / menu clearly' },
  { key: 'key_visual_direction', title: 'Key Visual Direction', platform: 'Cross-channel', format: 'Master key visual', objective: 'Define the campaign visual system' },
  { key: 'designer_handoff_notes', title: 'Designer Handoff Notes', platform: 'Internal', format: 'Handoff document', objective: 'Hand the spec to the designer cleanly' }
];
const items = specs.map((spec) => ({
  key: spec.key,
  title: spec.title,
  platform: spec.platform,
  format: spec.format,
  objective: spec.objective,
  target_audience: audience,
  visual_direction: `Hero ${product} in a clean, appetizing ${brand} frame. No live publishing. Real photography only — no image generation.`,
  layout_guidance: spec.key === 'designer_handoff_notes' ? 'Provide layered source, fonts, export specs, safe margins.' : 'Clear focal point, legible text, generous safe margins.',
  copy_text: `Headline idea: ${brand} — ${spec.objective}. Offer: ${offer}.`,
  brand_style: colors,
  image_requirements: 'Owner-provided real product photography only. No AI image generation in this V1 flow.',
  cta: goal === 'sales' ? 'Inbox to order' : goal === 'lead' ? 'Leave your contact' : 'Follow for more',
  generated_by: 'n8n-ai-provider-placeholder',
  workflow_type: 'design_brief',
  status: 'pending_approval',
  owner_approval_required: true
}));
return [{ json: {
  ok: true,
  request_id: request.request_id,
  workflow_type: 'design_brief',
  generated_by: 'n8n-ai-provider-placeholder',
  owner_approval_required: true,
  status: 'pending_approval',
  job: {
    external_execution_id: $execution.id,
    item_count: items.length
  },
  items,
  safety: request.safety
}}];
